const lead = $('Execute Workflow Trigger').first().json;
const categoriaMapeada = lead.categoria_mapeada || 'Saúde/estética';

const httpItem = $input.first();
const httpHtml = httpItem.json.data || httpItem.json.body || '';
const httpError = !!httpItem.json.error || (httpItem.json.statusCode && httpItem.json.statusCode >= 400);

if (httpError || typeof httpHtml !== 'string' || httpHtml.length < 100) {
  return [{
    json: {
      nome: lead.nome || '',
      telefone: lead.telefone || '',
      endereco: lead.endereco || '',
      site: lead.url_site || lead.site || '',
      categoria_mapeada: categoriaMapeada,
      canal: lead.canal || '',
      tem_site: true,
      site_inacessivel: true,
      prompt: '',
      ollamaRequest: '',
    }
  }];
}

function filtrarHTML(rawHtml) {
  let filtrado = rawHtml
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<!--[\s\S]*?-->/g, '');

  const titleMatch = filtrado.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
  const title = titleMatch ? `TITLE: ${titleMatch[1].trim()}` : '';

  const metas = [];
  const metaRe = /<meta[^>]+>/gi;
  let m;
  while ((m = metaRe.exec(filtrado)) !== null) {
    if (/description|viewport|charset|keywords/i.test(m[0])) {
      metas.push(m[0].replace(/\s+/g, ' ').trim());
    }
  }

  const headings = [];
  const headRe = /<h([1-6])[^>]*>([\s\S]*?)<\/h\1>/gi;
  while ((m = headRe.exec(filtrado)) !== null) {
    const texto = m[2].replace(/<[^>]+>/g, '').trim();
    if (texto) headings.push(`H${m[1]}: ${texto}`);
  }

  const hrefs = [];
  const hrefRe = /href=["']([^"']+)["']/gi;
  while ((m = hrefRe.exec(filtrado)) !== null) {
    if (!m[1].startsWith('#') && m[1].trim()) hrefs.push(m[1].trim());
  }

  const imgs = [];
  const imgRe = /<img[^>]+>/gi;
  while ((m = imgRe.exec(filtrado)) !== null) {
    const alt = (m[0].match(/alt=["']([^"']*)["']/i) || [])[1] || '';
    const src = (m[0].match(/src=["']([^"']*)["']/i) || [])[1] || '';
    imgs.push(`IMG alt="${alt}" src="${src.substring(0, 60)}"`);
  }

  const textoLimpo = filtrado
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .substring(0, 1000);

  return [
    title,
    metas.length    ? 'METAS:\n'    + metas.slice(0, 5).join('\n')    : '',
    headings.length ? 'HEADINGS:\n' + headings.slice(0, 8).join('\n') : '',
    hrefs.length    ? 'LINKS:\n'    + hrefs.slice(0, 10).join('\n')   : '',
    imgs.length     ? 'IMAGENS:\n'  + imgs.slice(0, 6).join('\n')     : '',
    textoLimpo      ? 'TEXTO:\n'    + textoLimpo                       : '',
  ].filter(Boolean).join('\n\n');
}

const htmlFiltrado = filtrarHTML(httpHtml);
const needs_screenshot = htmlFiltrado.length < 300;
const htmlTruncado = htmlFiltrado.substring(0, 1000);

const PROMPTS = {
  'Saúde/estética': `Você é um consultor de presença digital para pequenas empresas brasileiras. Analise o HTML abaixo de um site de clínica, consultório ou estabelecimento de saúde/estética e identifique 2 a 3 elementos importantes que estão FALTANDO ou mal implementados, que podem estar fazendo esse negócio perder pacientes ou clientes.\n\nUm site de saúde/estética que converte bem precisa ter:\n- Botão de WhatsApp ou agendamento visível logo no topo da página\n- Lista clara dos serviços ou tratamentos oferecidos com descrição simples (não só o nome)\n- Foto e nome dos profissionais que atendem (paciente quer saber quem vai atender antes de marcar)\n- Depoimentos reais de pacientes ou clientes\n- Endereço completo, horário de funcionamento e mapa\n- Site rápido e funcional no celular\n- Certificado de segurança (https) ativo\n\nAnalise o HTML e identifique o que está faltando ou poderia melhorar. Foque nos elementos que mais impactam a decisão do paciente de entrar em contato.\n\nRegras: português brasileiro natural e direto, linguagem que um dono de clínica sem conhecimento técnico entenda, foque no impacto para o negócio. Retorne APENAS JSON válido sem texto fora do JSON. Formato: {"problemas": ["problema 1", "problema 2"], "severidade": "critico" ou "melhoria"}. severidade = critico se falta botão de contato, lista de serviços ou o site não funciona no celular.\n\nHTML: [HTML_AQUI]`,
  'Serviços profissionais': `Você é um consultor de presença digital para pequenas empresas brasileiras. Analise o HTML abaixo de um site de escritório profissional (advocacia, contabilidade, arquitetura, imobiliária ou consultoria) e identifique 2 a 3 elementos importantes que estão FALTANDO ou mal implementados, que podem estar fazendo esse negócio perder clientes.\n\nUm site de serviços profissionais que converte bem precisa ter:\n- Especialidades ou áreas de atuação explicadas claramente logo na entrada (cliente precisa saber em segundos se você resolve o problema dele)\n- Credenciais visíveis: tempo de experiência, registro profissional (OAB, CRC, CAU), número de casos atendidos\n- Formulário de contato simples ou WhatsApp direto de fácil acesso\n- Depoimentos de clientes reais com nome e contexto\n- Seção de perguntas frequentes ou explicação do processo de atendimento\n- Informação de localização e horário de atendimento\n\nRegras: português brasileiro natural e direto, linguagem que um advogado ou contador sem conhecimento técnico de web entenda. Retorne APENAS JSON válido. Formato: {"problemas": ["problema 1", "problema 2"], "severidade": "critico" ou "melhoria"}. severidade = critico se não há forma clara de contato ou especialidades não descritas.\n\nHTML: [HTML_AQUI]`,
  'Comércio/loja física': `Você é um consultor de presença digital para pequenas empresas brasileiras. Analise o HTML abaixo de um site de loja física (roupas, móveis, decoração, joalheria ou presentes) e identifique 2 a 3 elementos importantes que estão FALTANDO ou mal implementados, que podem estar fazendo essa loja perder clientes antes mesmo de eles visitarem o espaço físico.\n\nUm site de loja física que converte bem precisa ter:\n- Galeria ou catálogo de produtos com fotos de qualidade (cliente quer ver o produto antes de ir até a loja)\n- Botão de WhatsApp visível para tirar dúvidas ou checar disponibilidade\n- Endereço completo com mapa e horário de funcionamento em destaque\n- Pelo menos uma indicação de faixa de preço ou promoção ativa\n- Link para Instagram atualizado (prova visual do estoque)\n- Site funcional no celular\n\nRegras: português brasileiro natural e direto, linguagem que um dono de loja sem conhecimento técnico entenda. Retorne APENAS JSON válido. Formato: {"problemas": ["problema 1", "problema 2"], "severidade": "critico" ou "melhoria"}. severidade = critico se não há fotos de produto, endereço ou forma de contato visível.\n\nHTML: [HTML_AQUI]`,
  'Eventos/hospedagem': `Você é um consultor de presença digital para pequenas empresas brasileiras. Analise o HTML abaixo de um site de buffet, espaço para eventos, pousada ou hotel e identifique 2 a 3 elementos importantes que estão FALTANDO ou mal implementados, que podem estar fazendo esse negócio perder reservas e contratos.\n\nUm site de eventos/hospedagem que converte bem precisa ter:\n- Galeria de fotos do espaço físico com qualidade e variedade (elemento mais decisivo — cliente compra visualmente)\n- Capacidade do espaço e tipos de evento atendidos descritos claramente (casamento, aniversário, corporativo, quantos convidados)\n- Formulário de orçamento ou WhatsApp direto de fácil acesso\n- Depoimentos ou fotos de eventos reais já realizados no espaço\n- Localização com mapa e como chegar\n- Informação de disponibilidade ou como verificar datas livres\n\nRegras: português brasileiro natural e direto, linguagem que um dono de buffet ou pousada sem conhecimento técnico entenda. Retorne APENAS JSON válido. Formato: {"problemas": ["problema 1", "problema 2"], "severidade": "critico" ou "melhoria"}. severidade = critico se não há galeria de fotos do espaço ou forma de solicitar orçamento.\n\nHTML: [HTML_AQUI]`
};

const promptTemplate = PROMPTS[categoriaMapeada] || PROMPTS['Saúde/estética'];
const prompt = promptTemplate.replace('[HTML_AQUI]', htmlTruncado);

const ollamaRequest = JSON.stringify({
  model: 'mistral',
  prompt: prompt,
  stream: false,
  options: { num_predict: 200, temperature: 0.1 },
});

return [{
  json: {
    nome: lead.nome || '',
    telefone: lead.telefone || '',
    endereco: lead.endereco || '',
    site: lead.url_site || lead.site || '',
    categoria_mapeada: categoriaMapeada,
    canal: lead.canal || '',
    tem_site: true,
    site_inacessivel: false,
    needs_screenshot,
    prompt,
    ollamaRequest,
  }
}];

const filterData = $('Filtrar HTML e Selecionar Prompt').first().json;
const ollamaItem = $input.first().json;
const respostaRaw = ollamaItem.response || '';

function extrairJSON(texto) {
  const match = texto.match(/\{[\s\S]*\}/);
  if (match) {
    try { return JSON.parse(match[0]); } catch (_) {}
  }
  const inicio = texto.indexOf('{');
  if (inicio !== -1) {
    const candidato = texto.slice(inicio).trim();
    for (const t of [candidato + '}', candidato + '"melhoria"}']) {
      try { return JSON.parse(t); } catch (_) {}
    }
  }
  return null;
}

let problemas_encontrados = [];
let severidade = 'erro_parse';

if (respostaRaw) {
  const parsed = extrairJSON(respostaRaw);
  if (parsed && Array.isArray(parsed.problemas) && parsed.problemas.length > 0) {
    problemas_encontrados = parsed.problemas;
    severidade = ['critico', 'melhoria'].includes(parsed.severidade) ? parsed.severidade : 'melhoria';
  }
}

return [{
  json: {
    nome: filterData.nome || '',
    telefone: filterData.telefone || '',
    endereco: filterData.endereco || '',
    site: filterData.site || '',
    categoria_mapeada: filterData.categoria_mapeada || '',
    canal: filterData.canal || '',
    tem_site: true,
    problemas_encontrados,
    severidade,
  }
}];

const item = $input.first().json;
return [{
  json: {
    nome: item.nome || '',
    telefone: item.telefone || '',
    endereco: item.endereco || '',
    site: item.site || item.url_site || '',
    categoria_mapeada: item.categoria_mapeada || '',
    canal: item.canal || '',
    tem_site: true,
    problemas_encontrados: [],
    severidade: 'erro_acesso',
  }
}];
